/* Estilo para un botón moderno */
.btn-primary {
  background-color: #3b82f6;
  color: white;
  padding: 10px 20px;
  border: none;
  border-radius: 8px;
  transition: background-color 0.3s ease;
}

.btn-primary:hover {
  background-color: #2563eb;
}

// Función para saludar al usuario
function saludar(nombre) {
  return `¡Hola, ${nombre}! Bienvenido a Techpedia.`;
}

// Event listener para un botón
document.querySelector('#btn-saludo').addEventListener('click', () => {
  const mensaje = saludar('Estudiante');
  console.log(mensaje);
});

const http = require('http');

const server = http.createServer((req, res) => {
  res.statusCode = 200;
  res.setHeader('Content-Type', 'text/plain');
  res.end('¡Hola Servidor Node.js!\n');
});

server.listen(3000, () => {
  console.log('Servidor corriendo en http://localhost:3000/');
});

// Definimos una Interfaz que describe un objeto Usuario
interface Usuario {
  id: number;
  nombre: string;
  esEstudiante: boolean;
}

// Una función que recibe y retorna tipos específicos
function registrarUsuario(user: Usuario): string {
  if (user.esEstudiante) {
    return `Estudiante ${user.nombre} registrado con ID: ${user.id}`;
  }
  return `Usuario externo ${user.nombre} registrado.`;
}

